script:
function runFastAlsEasterEgg() {
    const output = document.getElementById('terminal-output');
    output.innerHTML = '';
    let pizzaContainer = document.getElementById('pizza-rain-container');
    if (!pizzaContainer) {
        pizzaContainer = document.createElement('div');
        pizzaContainer.id = 'pizza-rain-container';
        pizzaContainer.style.position = 'absolute';
        pizzaContainer.style.top = 0;
        pizzaContainer.style.left = 0;
        pizzaContainer.style.width = '100%';
        pizzaContainer.style.height = '100%';
        pizzaContainer.style.pointerEvents = 'none';
        pizzaContainer.style.zIndex = 10;
        output.appendChild(pizzaContainer);
    }
    const width = output.offsetWidth;
    const height = output.offsetHeight;
    const pizzaCount = Math.floor(width / 40);
    let pizzas = [];
    for (let i = 0; i < pizzaCount; i++) {
        const pizza = document.createElement('div');
        pizza.textContent = '🍕';
        pizza.style.position = 'absolute';
        pizza.style.left = (i * (width / pizzaCount)) + 'px';
        pizza.style.top = (-40 - Math.random() * 100) + 'px';
        pizza.style.fontSize = '2em';
        pizza.style.opacity = 0.9;
        pizzaContainer.appendChild(pizza);
        pizzas.push({ el: pizza, speed: 2 + Math.random() * 2 });
    }
    let running = true;
    function animatePizzas() {
        for (let p of pizzas) {
            let top = parseFloat(p.el.style.top);
            top += p.speed;
            if (top > height) {
                top = -40 - Math.random() * 100;
            }
            p.el.style.top = top + 'px';
        }
        if (running) requestAnimationFrame(animatePizzas);
    }
    animatePizzas();
    setTimeout(() => {
        running = false;
        if (pizzaContainer && pizzaContainer.parentNode) pizzaContainer.parentNode.removeChild(pizzaContainer);
    }, 10000);
}
runFastAlsEasterEgg();
